// // This module implements a 4-bit binary counter that decrements on each rising edge of the clock signal. If the reset input is asserted, the counter is initialized to zero. Once the counter reaches its minimum value of 0 (binary 0000), it wraps around and resets back to zero.
module top_module(
    q,
    clk,
    rst
);output reg [3:0] q;
    input clk;
    input rst;

    always @(posedge clk) begin
        if (rst) begin
            q <= 4'b0000;
        end else begin
            q <= q + 1;
            if (q == 4'b1111) begin
                q <= 4'b0000;
            end
        end
    end

endmodule
